#### **任务 0.2: 完善 WebSocket 连接管理（1 天）**

**工作量**: 6-8 小时  
**优先级**: ⭐⭐⭐⭐⭐  
**依赖**: 任务 0.1

**实现代码**:
```typescript
// dashboard/src/stores/websocket.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

export const useWebSocketStore = defineStore('websocket', () => {
  const ws = ref<WebSocket | null>(null)
  const isConnected = ref(false)
  const reconnectAttempts = ref(0)
  const maxReconnectAttempts = 5
  const reconnectDelay = ref(1000)

  // 心跳定时器
  let heartbeatTimer: number | null = null

  // 连接 WebSocket
  function connect() {
    if (ws.value?.readyState === WebSocket.OPEN) {
      return
    }

    const wsUrl = import.meta.env.VITE_WS_BASE_URL || 'ws://localhost:3000/api/ws'
    ws.value = new WebSocket(wsUrl)

    ws.value.onopen = () => {
      console.log('[WebSocket] 连接成功')
      isConnected.value = true
      reconnectAttempts.value = 0
      reconnectDelay.value = 1000

      // 启动心跳
      startHeartbeat()
    }

    ws.value.onmessage = (event) => {
      try {
        const { event: eventType, data } = JSON.parse(event.data)
        handleMessage(eventType, data)
      } catch (error) {
        console.error('[WebSocket] 消息解析错误:', error)
      }
    }

    ws.value.onclose = () => {
      console.log('[WebSocket] 连接关闭')
      isConnected.value = false
      stopHeartbeat()

      // 自动重连
      if (reconnectAttempts.value < maxReconnectAttempts) {
        const delay = reconnectDelay.value * (reconnectAttempts.value + 1)
        console.log(`[WebSocket] ${delay}ms 后尝试重连...`)

        setTimeout(() => {
          reconnectAttempts.value++
          connect()
        }, delay)
      }
    }

    ws.value.onerror = (error) => {
      console.error('[WebSocket] 连接错误:', error)
    }
  }

  // 启动心跳
  function startHeartbeat() {
    heartbeatTimer = window.setInterval(() => {
      if (ws.value?.readyState === WebSocket.OPEN) {
        ws.value.send(JSON.stringify({ event: 'ping' }))
      }
    }, 30000) // 30 秒
  }

  // 停止心跳
  function stopHeartbeat() {
    if (heartbeatTimer) {
      clearInterval(heartbeatTimer)
      heartbeatTimer = null
    }
  }

  // 处理消息
  function handleMessage(event: string, data: any) {
    switch (event) {
      case 'connected':
        console.log('[WebSocket] 服务器确认连接:', data)
        break

      case 'pong':
        // 心跳响应
        break

      case 'iteration.status_changed':
        // 通知迭代 Store
        useIterationStore().updateIteration(data)
        break

      case 'iteration.progress':
        useIterationStore().updateProgress(data.progress)
        break

      case 'agent.status_changed':
        useAgentStore().updateAgent(data)
        break

      case 'agent.progress':
        useAgentStore().updateAgentProgress(data.name, data.progress)
        break

      case 'system.metrics':
        useOverviewStore().updateMetrics(data)
        break

      case 'log.entry':
        // 添加到日志 Store
        break

      default:
        console.warn('[WebSocket] 未知事件:', event)
    }
  }

  // 断开连接
  function disconnect() {
    stopHeartbeat()
    ws.value?.close()
    ws.value = null
    isConnected.value = false
  }

  // 发送消息
  function send(event: string, data: any) {
    if (ws.value?.readyState === WebSocket.OPEN) {
      ws.value.send(JSON.stringify({ event, data }))
    } else {
      console.warn('[WebSocket] 未连接，无法发送消息')
    }
  }

  return {
    isConnected,
    reconnectAttempts,
    connect,
    disconnect,
    send
  }
})
```

**验收标准**:
- ✅ WebSocket 自动连接
- ✅ 断线自动重连（最多 5 次）
- ✅ 30 秒心跳检测
- ✅ 事件正确路由到对应 Store

