// dashboard/src/stores/overview.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { api } from '@/services/api'

export interface SystemMetrics {
  totalIterations: number
  successfulIterations: number
  failedIterations: number
  activeAgents: number
  avgExecutionTime: number
  cpu: number
  memory: number
  uptime: number
  activeConnections: number
}

export const useOverviewStore = defineStore('overview', () => {
  const metrics = ref<SystemMetrics>({
    totalIterations: 0,
    successfulIterations: 0,
    failedIterations: 0,
    activeAgents: 0,
    avgExecutionTime: 0,
    cpu: 0,
    memory: 0,
    uptime: 0,
    activeConnections: 0
  })

  const loading = ref(false)
  const error = ref<string | null>(null)

  // 计算属性
  const successRate = computed(() => {
    if (metrics.value.totalIterations === 0) return 0
    return (metrics.value.successfulIterations / metrics.value.totalIterations * 100).toFixed(1)
  })

  // 更新系统指标
  function updateMetrics(data: Partial<SystemMetrics>) {
    Object.assign(metrics.value, data)
  }

  // 获取系统概览
  async function fetchOverview() {
    loading.value = true
    error.value = null

    try {
      const response = await api.get('/system/overview')
      metrics.value = {
        ...metrics.value,
        ...response.data
      }
    } catch (err: any) {
      error.value = err.message || '获取系统概览失败'
      console.error('[OverviewStore] 获取概览失败:', err)
    } finally {
      loading.value = false
    }
  }

  // 获取系统指标
  async function fetchMetrics() {
    try {
      const response = await api.get('/system/metrics')
      updateMetrics(response.data)
    } catch (err) {
      console.error('[OverviewStore] 获取指标失败:', err)
    }
  }

  // 检查健康状态
  async function checkHealth() {
    try {
      const response = await api.get('/system/health')
      return response.data
    } catch (err) {
      console.error('[OverviewStore] 健康检查失败:', err)
      return null
    }
  }

  return {
    metrics,
    loading,
    error,
    successRate,
    updateMetrics,
    fetchOverview,
    fetchMetrics,
    checkHealth
  }
})
```

**验收标准**:
- ✅ 能获取系统概览数据
- ✅ 成功率计算正确
- ✅ WebSocket 更新实时响应

