```typescript
// dashboard/src/stores/iteration.ts
import { defineStore } from 'pinia'
import { ref } from 'vue'
import { api } from '@/services/api'

export interface Iteration {
  id: string
  iterationNumber: number
  requirement: string
  pmAnalysis?: string
  status: 'running' | 'success' | 'failed'
  progress: number
  agents: any[]
  startedAt: string
  completedAt?: string
  duration?: number
}

export const useIterationStore = defineStore('iteration', () => {
  const iterations = ref<Iteration[]>([])
  const currentIteration = ref<Iteration | null>(null)
  const loading = ref(false)
  const total = ref(0)

  // 更新迭代状态
  function updateIteration(iteration: Iteration) {
    const index = iterations.value.findIndex(i => i.id === iteration.id)

    if (index !== -1) {
      // 更新现有迭代
      iterations.value[index] = iteration
    } else {
      // 添加新迭代
      iterations.value.unshift(iteration)
    }

    // 如果是当前迭代，更新当前迭代
    if (iteration.status === 'running') {
      currentIteration.value = iteration
    } else if (currentIteration.value?.id === iteration.id) {
      currentIteration.value = null
    }
  }

  // 更新迭代进度
  function updateProgress(progress: number) {
    if (currentIteration.value) {
      currentIteration.value.progress = progress
    }
  }

  // 获取迭代列表
  async function fetchIterations(params: {
    page: number
    pageSize: number
    status?: string
    keyword?: string
  }) {
    loading.value = true

    try {
      const response = await api.get('/iterations', { params })
      iterations.value = response.data.data
      total.value = response.data.total

      // 找到当前运行的迭代
      const running = iterations.value.find(i => i.status === 'running')
      if (running) {
        currentIteration.value = running
      }
    } catch (err) {
      console.error('[IterationStore] 获取迭代列表失败:', err)
    } finally {
      loading.value = false
    }
  }

  // 获取迭代详情
  async function fetchIterationDetail(id: string) {
    try {
      const response = await api.get(`/iterations/${id}`)
      return response.data
    } catch (err) {
      console.error('[IterationStore] 获取迭代详情失败:', err)
      return null
    }
  }

  // 回滚迭代
  async function rollbackIteration(id: string) {
    try {
      const response = await api.post(`/iterations/${id}/rollback`)
      return response.data
    } catch (err) {
      console.error('[IterationStore] 回滚失败:', err)
      throw err
    }
  }

  return {
    iterations,
    currentIteration,
    loading,
    total,
    updateIteration,
    updateProgress,
    fetchIterations,
    fetchIterationDetail,
    rollbackIteration
  }
})
```

